// Read webhook body: website_link (or url), pages_to_crawl (or max_crawl_pages), and email
const item = $input.first().json;
const body = item.body || item;

// 1) Website URL
const rawUrl = (body.website_link || body.url || body.website || '').toString().trim();
if (!rawUrl) {
  throw new Error('Missing website link. Send JSON like: { "website_link": "https://example.com/", "pages_to_crawl": 100, "email": "user@example.com" }');
}

const startUrl = rawUrl.startsWith('http') ? rawUrl : 'https://' + rawUrl;
let domain = '';
try {
  domain = new URL(startUrl).hostname.replace(/^www\./i, '');
} catch (e) {
  domain = rawUrl
    .replace(/^https?:\/\//i, '')
    .replace(/^www\./i, '')
    .split('/')[0]
    .split('?')[0]
    .trim();
}

// 2) Pages to crawl
const maxCrawlPages = Math.min(
  2000,
  Math.max(
    1,
    parseInt(body.pages_to_crawl || body.max_crawl_pages || 100, 10) || 100,
  ),
);

// 3) Email (for SMTP node later)
const email = (body.email || body.to || '').toString().trim();

return [
  {
    json: {
      domain,
      start_url: startUrl,
      max_crawl_pages: maxCrawlPages,
      email, // <‑‑ make available to later nodes
    },
  },
];

const startCrawl = $('Start On-Page Crawl').first().json;
const taskIdFromPost = startCrawl?.tasks?.[0]?.id;
const targetFromPost = startCrawl?.tasks?.[0]?.data?.target;

const tasksReady = $('Check Tasks Ready').first().json;
const results = tasksReady?.tasks?.[0]?.result || [];

const ourTask = results.find(r => r.id === taskIdFromPost || (targetFromPost && r.target && r.target.replace(/^https?:\/\//i, '').replace(/^www\./, '').includes(targetFromPost))) || results[0];
const taskId = ourTask?.id || taskIdFromPost;

if (!taskId) {
  throw new Error('No task id found. Crawl may not be ready yet. Increase Wait time and run again.');
}

return [{ json: { task_id: taskId, target: ourTask?.target || targetFromPost } }];

const input = $input.first().json;
const result = input?.tasks?.[0]?.result?.[0];
const items = result?.items || [];

const rows = items
  .filter(page => page.resource_type === 'html' && page.meta)
  .map(page => ({
    url: page.url || '',
    meta_title: page.meta.title || page.meta.meta_title || '',
    meta_description: page.meta.description || '',
    status_code: page.status_code,
    onpage_score: page.onpage_score
  }));

return rows.map(row => ({ json: row }));

return [
  {
    json: {
      version: "0.1.20260223",
      status_code: 20000,
      status_message: "Ok.",
      time: "0.1149 sec.",
      cost: 0.00125,
