            max_crawl_pages: 10,
            start_url: "https://delta-solution.co.uk/"
          },
          result: null
        }
      ]
    }
  }
];

const rows = $input.all().map(item => item.json);
const jsonStr = JSON.stringify(rows, null, 2);

return [
  {
    json: {},
    binary: {
      file: {                    // <-- binary field name MUST be "file"
        data: Buffer.from(jsonStr).toString('base64'),
        mimeType: 'application/json',
        fileName: 'temp.json'    // placeholder, Drive will override with File Name field
      }
    }
  }
];

