// ── 1. User Account Data ──────────────────────────────────────
const userDataResponse = $node["DataForSEO User Data"].json;

if (!userDataResponse?.tasks?.[0]?.result?.[0]?.money) {
  throw new Error('Unexpected user_data structure or missing money section.');
}

const money = userDataResponse.tasks[0].result[0].money;
const totalDeposited = Number(money.total);
const currentBalance = Number(money.balance);
const totalSpent = totalDeposited - currentBalance;

// ── 2. Read Costs from Each Node Response ─────────────────────
const crawlResponse     = $node["Start On-Page Crawl"].json;
const tasksReadyResponse = $node["Check Tasks Ready"].json;
const pagesResponse     = $node["Get On-Page Pages"].json;

const crawlCost      = Number(crawlResponse?.cost ?? 0);
const tasksReadyCost = Number(tasksReadyResponse?.cost ?? 0);
const pagesCost      = Number(pagesResponse?.cost ?? 0);
const userDataCost   = Number(userDataResponse?.cost ?? 0);

// ── 3. Sum of All API Calls This Session ──────────────────────
const totalSessionCost = crawlCost + tasksReadyCost + pagesCost + userDataCost;

// ── 4. Return Everything ──────────────────────────────────────
return [
  {
    json: {
      // Account balance info
      totalDeposited,
      currentBalance,
      totalSpent,

      // Cost per endpoint
      costs: {
        startOnPageCrawl:  crawlCost,
        checkTasksReady:   tasksReadyCost,
        getOnPagePages:    pagesCost,
        getUserData:       userDataCost,
      },

      // Total cost of this session's API calls
      totalSessionCost,

      // Balance after this session
      balanceAfterSession: currentBalance - totalSessionCost,
    },
  },
];

// We receive 2 items from Merge (Append):
// items[0] = Drive file info
// items[1] = Spend info

